import{_ as i,o as l,c as e,a3 as t}from"./chunks/framework.gsMzR_Kb.js";const u=JSON.parse('{"title":"变易","description":"变易帮助人把经典从固定教条中解放出来，重新看到“变化”才是《易》的核心语感。","frontmatter":{"title":"变易","description":"变易帮助人把经典从固定教条中解放出来，重新看到“变化”才是《易》的核心语感。","category":"guide","aliases":["变易","变易专题","bian yi"]},"headers":[],"relativePath":"topics/bian-yi.md","filePath":"topics/bian-yi.md","lastUpdated":1777132262000}'),r={name:"topics/bian-yi.md"};function o(n,a,s,h,d,c){return l(),e("div",null,[...a[0]||(a[0]=[t('<h1 id="变易" tabindex="-1">变易 <a class="header-anchor" href="#变易" aria-label="Permalink to &quot;变易&quot;">​</a></h1><h2 id="是什么" tabindex="-1">是什么 <a class="header-anchor" href="#是什么" aria-label="Permalink to &quot;是什么&quot;">​</a></h2><p>变易不是一句“万物都在变”的空话，而是《易经》最基本的世界观之一。</p><p>它提醒人：</p><ul><li>情势会变</li><li>位置会变</li><li>关系会变</li><li>同样的方法，放在不同阶段也会变得不合适</li></ul><p>所以读《易》，一定要学会看转折、看过程、看由此到彼的脉络。</p><h2 id="为什么重要" tabindex="-1">为什么重要 <a class="header-anchor" href="#为什么重要" aria-label="Permalink to &quot;为什么重要&quot;">​</a></h2><p>若不理解变易，《易经》就会被读成静态分类学。</p><ul><li>卦只剩名字</li><li>爻只剩吉凶</li><li>经典只剩结论</li></ul><p>而一旦抓住变易，很多卦的意义就会活起来：它们不再只是告诉你“现在是什么”，而是在展示“事情如何走到这里、又可能如何继续变化”。</p><h2 id="怎么读-怎么进入" tabindex="-1">怎么读 / 怎么进入 <a class="header-anchor" href="#怎么读-怎么进入" aria-label="Permalink to &quot;怎么读 / 怎么进入&quot;">​</a></h2><p>建议先从这三个问题进入：</p><ol><li>这件事现在处在哪个阶段？</li><li>它为什么会从前一阶段走到这里？</li><li>下一步最可能的变化方向是什么？</li></ol><p>然后再回到卦爻与《系辞》里看，会更容易理解《易》为何如此重“时”和“位”。</p><h2 id="相关原典" tabindex="-1">相关原典 <a class="header-anchor" href="#相关原典" aria-label="Permalink to &quot;相关原典&quot;">​</a></h2><ul><li>《周易》</li><li>《系辞上传》</li><li>《系辞下传》</li><li>《道德经》</li></ul><h2 id="我的理解" tabindex="-1">我的理解 <a class="header-anchor" href="#我的理解" aria-label="Permalink to &quot;我的理解&quot;">​</a></h2><p>待补：这里先留给后续把自己对“变易如何帮助理解现实变化”的经验补进来。</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to &quot;参考来源&quot;">​</a></h2><ul><li>《周易》</li><li><a href="/Dao/yijing/basics/concepts/bian-yi">易经概念：变易</a></li></ul>',20)])])}const b=i(r,[["render",o]]);export{u as __pageData,b as default};
